import{c as a,S as i,j as t,m as r}from"./chunks/framework.BXgR76oC.js";const h=JSON.parse('{"title":"Privacy And Security","description":"","frontmatter":{},"headers":[],"relativePath":"security/privacy.md","filePath":"security/privacy.md","lastUpdated":1779780644000}'),s={name:"security/privacy.md"};function l(n,e,o,c,d,u){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="privacy-and-security" tabindex="-1">Privacy And Security <a class="header-anchor" href="#privacy-and-security" aria-label="Permalink to “Privacy And Security”">​</a></h1><p>Gittensory handles contribution intelligence, not wallets or private source code.</p><h2 id="no-pat-storage" tabindex="-1">No PAT Storage <a class="header-anchor" href="#no-pat-storage" aria-label="Permalink to “No PAT Storage”">​</a></h2><p>MCP login uses GitHub OAuth Device Flow. The backend exchanges the GitHub token for a Gittensory session token and stores only the hashed Gittensory token server-side.</p><h2 id="no-source-upload" tabindex="-1">No Source Upload <a class="header-anchor" href="#no-source-upload" aria-label="Permalink to “No Source Upload”">​</a></h2><p>Local MCP branch analysis sends metadata only:</p><ul><li>repo full name</li><li>branch name</li><li>base and head refs</li><li>changed file paths</li><li>additions and deletions</li><li>linked issue references</li><li>commit messages</li><li>validation summaries</li></ul><p>Source contents are not uploaded in v1. <code>GITTENSORY_UPLOAD_SOURCE=true</code> fails closed.</p><h2 id="public-output-boundaries" tabindex="-1">Public Output Boundaries <a class="header-anchor" href="#public-output-boundaries" aria-label="Permalink to “Public Output Boundaries”">​</a></h2><p>Public comments and public-safe PR packets must not include:</p><ul><li>wallets</li><li>hotkeys</li><li>raw trust scores</li><li>public score estimates</li><li>public reward estimates</li><li>farming language</li><li>public shaming</li></ul><p>Private API and MCP responses can include scoreability and reward/risk reasoning because they are authenticated private outputs.</p><h2 id="rate-limiting" tabindex="-1">Rate Limiting <a class="header-anchor" href="#rate-limiting" aria-label="Permalink to “Rate Limiting”">​</a></h2><p>Gittensory uses route classes:</p><ul><li>strict: auth routes</li><li>normal: read APIs and MCP tools</li><li>expensive: branch analysis, scoring preview, decision-pack refresh, signal refresh</li></ul><p>Rate-limited responses return <code>429</code> with retry metadata.</p><h2 id="github-app-boundaries" tabindex="-1">GitHub App Boundaries <a class="header-anchor" href="#github-app-boundaries" aria-label="Permalink to “GitHub App Boundaries”">​</a></h2><p>The GitHub App is advisory-only. It does not auto-label, close, merge, or rewrite contributor work.</p>',18)])])}const b=a(s,[["render",l]]);export{h as __pageData,b as default};
